import Foundation
import UIKit


enum EndPoint {
    case auth
    case fetch
}
let baseUrlString = "https://api.example.com"
final class Service {
    
    static let sharedInstance = Service()
    private init(){}
    
    func request(method: String, endpoint: EndPoint, body:[String : AnyObject], completion:@escaping (Data?, Error?)->())  {
        
        guard let urlComponents = URLComponents(string:"\(baseUrlString)/\(endpoint)") else{
            return
        }
        var urlRequest = URLRequest(url: urlComponents.url!)
        urlRequest.httpMethod = method
        do {
            if body.count > 0 {
                try urlRequest.httpBody = JSONSerialization.data(withJSONObject: body, options: .prettyPrinted)
            }
            
            let task = URLSession.shared.dataTask(with: urlRequest){ data , response , error in
                
                guard let dataResponse = data else{
                    completion(nil,error!)
                    
                    return
                }
                do {
                   try JSONSerialization.jsonObject(with: dataResponse, options: .allowFragments)
                   completion(dataResponse, nil)
                    
                } catch let jsonError {
                    print(jsonError)
                    completion(nil , error!)
                }
            }
            task.resume()
        }catch{
            
        }
    }
}